SET @demo_user_id = (SELECT id FROM users WHERE openId = 'demo_partner_prolink_2026' LIMIT 1);
SET @scoop_duke_id = (SELECT id FROM partners WHERE businessName = 'Scoop Duke DFW' LIMIT 1);

-- Link the Scoop Duke partner to the demo user
UPDATE partners SET userId = @demo_user_id WHERE id = @scoop_duke_id;

-- Confirm
SELECT u.id as userId, u.name, u.openId, p.id as partnerId, p.businessName, p.tier, p.status 
FROM users u JOIN partners p ON p.userId = u.id 
WHERE u.openId = 'demo_partner_prolink_2026';

